`define FORCE_MPLL_COARSE_TUNE_INST(mpll_sel, mpllb_sel) \
	dwc_pcie5_phy_x4_ns_force_mpll_coarse_tune #(.MPLLB_SEL(mpllb_sel)) force_mpll``mpll_sel``_coarse_tune (\
	   .mpll_en(pma.mpll``mpll_sel``_ana_en), \
	   .ref_ana_clk(pma.ana.sup.prescaler.ref_mpll``mpll_sel``_clk), \
	   .ref_clk_mpll_div(3'b0), \
	   .mpll_div_clk_div4_en(pma.mpll``mpll_sel``_ana_fb_clk_div4_en), \
	   .mpll_multiplier(pma.dig.sup.mpll``mpll_sel``_multiplier_i), \
	   .mpll_frac_en(pma.dig.sup.mpll``mpll_sel``_frac_en_i), \
	   .mpll_frac_quot(pma.dig.sup.mpll``mpll_sel``_frac_quot_i), \
	   .mpll_ana_coarse_tune(pma.mpll``mpll_sel``_ana_coarse_tune) \
	);

`FORCE_MPLL_COARSE_TUNE_INST(a, 0)
`FORCE_MPLL_COARSE_TUNE_INST(b, 1)

`endif // DWC_PCIE5_X4NS_HW_EMU
