	   .ref_ana_div2_en(pcs_raw.aon.lane1_ref_sel_i ? pma.dig.sup.refb_clk_div2_en_i : pma.dig.sup.refa_clk_div2_en_i),
	   .rx_ref_ld_val(pma.dig.lane1.rx_ref_ld_val_i),
	   .rx_vco_ld_val(pma.dig.lane1.rx_vco_ld_val_i),
	   .rx_cdr_vco_config(pma.dig.lane1.rx_cdr_vco_config_i),
