	   .ref_ana_div2_en(pcs_raw.aon.lane2_ref_sel_i ? pma.dig.sup.refb_clk_div2_en_i : pma.dig.sup.refa_clk_div2_en_i),
	   .rx_ref_ld_val(pma.dig.lane2.rx_ref_ld_val_i),
	   .rx_vco_ld_val(pma.dig.lane2.rx_vco_ld_val_i),
	   .rx_cdr_vco_config(pma.dig.lane2.rx_cdr_vco_config_i),
	   .rx_ana_cdr_freq_tune(pma.rx2_ana_cdr_freq_tune),
	   .rx_ana_cdr_freq_tune_clk(pma.rx2_ana_cdr_freq_tune_clk),
	   .rx_margin_in_prog(rx2_margin_in_prog),
	   .rx_adapt_in_prog(rx2_adapt_in_prog),
	   .rx_data_en(rx2_data_en),
	   .rx_ana_iqc_data_adjust(pma.ana.rx2_ana_iqc_data_adjust),
	   .rx_rate(rx2_pma_rate),
	   .rx_width(rx2_pma_width)
	);

	dwc_pcie5_phy_x4_ns_force_freq_tune force_freq_tune3 (
	   .ref_ana_clk(pma.lane3_ref_clk),
	   .phy_reset(pma.phy_reset),
	   .ref_ana_clk_en(pcs_raw.aon.lane3_ref_sel_i ? pma.refb_clk_en : pma.refa_clk_en),
	   .ref_ana_div2_en(pcs_raw.aon.lane3_ref_sel_i ? pma.dig.sup.refb_clk_div2_en_i : pma.dig.sup.refa_clk_div2_en_i),
	   .rx_ref_ld_val(pma.dig.lane3.rx_ref_ld_val_i),
	   .rx_vco_ld_val(pma.dig.lane3.rx_vco_ld_val_i),
	   .rx_cdr_vco_config(pma.dig.lane3.rx_cdr_vco_config_i),
	   .rx_ana_cdr_freq_tune(pma.rx3_ana_cdr_freq_tune),
	   .rx_ana_cdr_freq_tune_clk(pma.rx3_ana_cdr_freq_tune_clk),
	   .rx_margin_in_prog(rx3_margin_in_prog),
